parameters.jsCode:
const body = $json.body || $json;
const company = body.company || body.business_name || "";
const title = body.title || body.role || "";
return [{
  json: {
    customerId: body.customerId || body.customer_id,
    callId: body.callId || body.call_id || "",
    name: body.name || "Customer",
    company,
    title,
    transcript: body.transcript || "",
    callSummary: body.summary || "",
    search_query: [company, title].filter(Boolean).join(" ") + " company role background"
  }
}];

const source = $("Normalize Intelligence Context").item.json;
const results = $json.organic_results || [];
const snippets = results.slice(0, 5).map(item => `${item.title || ""}: ${item.snippet || ""} (${item.link || ""})`).join("\n");
const website = (results.find(item => String(item.link || "").startsWith("http")) || {}).link || "";
return [{ json: { ...source, website, snippets } }];

parameters.text:
=Create a CRM intelligence profile from call context and search snippets. Return JSON only.

Required shape:
{
  "background_summary": "customer profile summary",
  "company_summary": "company description",
  "role_summary": "what this person's title/role likely means",
  "pain_points": "pain points from call",
  "needs": "customer needs from call",
  "budget": "budget signal or unknown",
  "decision_authority": "decision maker / influencer / unknown",
  "source_notes": "sources and caveats"
}

Customer: {{ $json.name }}
Company: {{ $json.company }}
Title: {{ $json.title }}
Call summary: {{ $json.callSummary }}
Transcript:
{{ $json.transcript }}

Search snippets:
{{ $json.snippets }}

parameters.jsCode:
const raw = $json.output || "{}";
let parsed;
try { parsed = JSON.parse(String(raw).replace(/```json|```/g, "").trim()); } catch (error) { parsed = {}; }
const source = $("Parse Search Context").item.json;
return {
  json: {
    ...source,
    background_summary: parsed.background_summary || source.callSummary || "",
    company_summary: parsed.company_summary || "",
    role_summary: parsed.role_summary || "",
    pain_points: parsed.pain_points || "",
    needs: parsed.needs || "",
    budget: parsed.budget || "Unknown",
    decision_authority: parsed.decision_authority || "Unknown",
    source_notes: parsed.source_notes || source.snippets || ""
  }
};
